def load_settings(defaults: dict, file_settings: dict, cli_settings: dict) -> dict:
    # Приоритет применения (от низшего к высшему):
    # defaults < file_settings < cli_settings (только не-None) < APP_PORT
    merged = {**defaults, **file_settings}

    for key, value in cli_settings.items():
        if value is not None:
            merged[key] = value

    env_port = os.environ.get("APP_PORT")
    if env_port is not None and env_port != "":
        try:
            merged["port"] = int(env_port)
        except ValueError:
            pass  # игнорируем некорректное значение окружения

    return merged

